/**
 * Clients Module - Compact Grid with Smart Expandable Cards
 * ✅ FIXED: Smart expand direction detection
 * ✅ FIXED: Prevent multiple cards open at once
 * ✅ FIXED: Maintain expanded state after reload
 * ✅ ENHANCED: Smooth transitions + rapid click protection
 */

const ClientsModule = (function() {
    let currentClients = [];
    let isInitialized = false;
    let isLoading = false;
    let expandedClientId = null;
    let expandedCardElement = null;
    let expandedDirection = null; 
    let isAnimating = false;
    let outsideClickBound = false;

    /** ===== HELPER FUNCTIONS ===== */

    function getAvatarColor(name) {
        const colors = ['#4361ee', '#4895ef', '#3f37c9', '#4cc9f0', '#06d6a0', '#ffb703', '#e63946', '#f72585', '#7209b7', '#560bad'];
        let hash = 0;
        for (let i = 0; i < name.length; i++) hash = ((hash << 5) - hash) + name.charCodeAt(i) | 0;
        return colors[Math.abs(hash) % colors.length];
    }

    function formatDateTime(dateString) {
        if (!dateString) return 'No date';
        try {
            const date = new Date(dateString);
            return date.toLocaleDateString('en-US', { weekday: 'short', hour: '2-digit', minute: '2-digit' });
        } catch { return 'Invalid date'; }
    }

    function forceCloseCard(card) {
        if (!card) return;
        const expandable = card.querySelector('[data-expandable="true"]');
        const chevron = card.querySelector('.chevron-icon');

        card.classList.remove('expanded', 'expand-up', 'expand-down');
        if (expandable) expandable.classList.remove('expanded');
        if (chevron) chevron.classList.remove('rotated');
    }

    /** ===== INIT ===== */
    function init() {
        if (isInitialized) return;
        bindEvents();
        loadClients();
        isInitialized = true;
        console.log('👥 Clients Module Initialized');
    }

    /** ===== EVENT BINDING ===== */
    function bindEvents() {
        const container = document.getElementById('clients-container');
        if (container) container.addEventListener('click', handleContainerClick);

        if (!outsideClickBound) {
            document.addEventListener('click', handleOutsideClick);
            outsideClickBound = true;
        }

        window.addEventListener('resize', () => {
            if (expandedCardElement) collapseExpandedCard();
        });
    }

    function handleContainerClick(e) {
        const toggleBtn = e.target.closest('[data-action="toggle"]');
        if (toggleBtn) {
            e.stopPropagation();
            const card = toggleBtn.closest('.compact-card');
            if (card) toggleCard(card.dataset.clientId);
            return;
        }

        const actionBtn = e.target.closest('[data-action]');
        if (actionBtn && actionBtn !== toggleBtn) {
            e.stopPropagation();
            handleCardAction(actionBtn);
        }
    }

    function handleCardAction(btn) {
        const action = btn.dataset.action;
        const id = btn.dataset.id;
        const phone = btn.dataset.phone;
        switch(action) {
            case 'call': return callClient(phone);
            case 'whatsapp': return whatsAppClient(phone);
            case 'edit': return editClient(id);
            case 'delete': return deleteClient(id);
            case 'view': return viewClientDetails(id);
        }
    }

    function handleOutsideClick(e) {
        if (!expandedCardElement) return;
        if (!expandedCardElement.contains(e.target)) collapseExpandedCard();
    }

    /** ===== COLLAPSE CARD ===== */
    function collapseExpandedCard() {
        if (!expandedCardElement || isAnimating) return;
        const card = expandedCardElement;
        const expandable = card.querySelector('[data-expandable="true"]');
        const chevron = card.querySelector('.chevron-icon');

        if (expandable) expandable.classList.remove('expanded');
        if (chevron) chevron.classList.remove('rotated');

        const handleTransitionEnd = () => {
            card.classList.remove('expanded', 'expand-up', 'expand-down');
            expandedCardElement = null;
            expandedClientId = null;
            expandedDirection = null;
            isAnimating = false;
            card.removeEventListener('transitionend', handleTransitionEnd);
        };

        card.addEventListener('transitionend', handleTransitionEnd, { once: true });

        setTimeout(handleTransitionEnd, 250);
    }

    /** ===== SMART EXPAND ===== */
    function toggleExpand(card) {
        if (isAnimating) return;

        const isExpanded = card.classList.contains('expanded');

        if (expandedCardElement && expandedCardElement !== card) {
            forceCloseCard(expandedCardElement);
            expandedCardElement = null;
            expandedClientId = null;
            expandedDirection = null;
        }

        if (isExpanded) return collapseExpandedCard();

        isAnimating = true;

        // DETECT SCROLL CONTAINER
        const gridContainer = card.closest('.clients-compact-grid');
        let scrollContainer = gridContainer;
        if (!scrollContainer || (getComputedStyle(scrollContainer).overflowY !== 'auto' && getComputedStyle(scrollContainer).overflowY !== 'scroll')) {
            scrollContainer = document.documentElement;
        }

        const containerRect = scrollContainer.getBoundingClientRect();
        const cardRect = card.getBoundingClientRect();
        const expandable = card.querySelector('[data-expandable="true"]');
        let neededSpace = expandable ? expandable.scrollHeight + 20 : 200;

        const spaceBelow = containerRect.bottom - cardRect.bottom;
        const spaceAbove = cardRect.top - containerRect.top;

        const openUpward = spaceBelow < neededSpace && spaceAbove > spaceBelow;

        if (openUpward) {
            card.classList.add('expanded', 'expand-up');
            card.classList.remove('expand-down');
            expandedDirection = 'up';
            card.scrollIntoView({ behavior: 'smooth', block: 'start' });
        } else {
            card.classList.add('expanded', 'expand-down');
            card.classList.remove('expand-up');
            expandedDirection = 'down';
            card.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }

        expandedCardElement = card;
        expandedClientId = card.dataset.clientId;

        const chevron = card.querySelector('.chevron-icon');
        if (chevron) chevron.classList.add('rotated');
        if (expandable) expandable.classList.add('expanded');

        const handleTransitionEnd = () => { isAnimating = false; card.removeEventListener('transitionend', handleTransitionEnd); };
        card.addEventListener('transitionend', handleTransitionEnd, { once: true });
        setTimeout(() => { isAnimating = false; }, 300);
    }

    function toggleCard(clientId) {
        const card = document.querySelector(`.compact-card[data-client-id="${clientId}"]`);
        if (!card) return;
        toggleExpand(card);
    }

    /** ===== LOAD CLIENTS ===== */
    async function loadClients() {
        const container = document.getElementById('clients-container');
        if (!container || isLoading) return;
        isLoading = true;

        try {
            container.innerHTML = '<div class="loading-overlay"><div class="spinner"></div><p>Loading clients...</p></div>';
            currentClients = await API.getClients();

            displayClients(currentClients);
        } catch (error) {
            container.innerHTML = '<div class="empty-state"><i class="fa-solid fa-triangle-exclamation"></i><h3>Error loading clients</h3></div>';
        } finally {
            isLoading = false;
        }
    }

    function displayClients(clients) {
        const container = document.getElementById('clients-container');
        if (!container) return;

        if (!clients || clients.length === 0) {
            container.innerHTML = `<div class="empty-state"><h3>No clients found</h3></div>`;
            return;
        }

        const sorted = [...clients].sort((a,b)=> new Date(b.registeredat||0)-new Date(a.registeredat||0));
        container.innerHTML = '<div class="clients-compact-grid">' + sorted.map(c => createCompactCard(c, c.id === expandedClientId)).join('') + '</div>';

        // Restore expanded card
        if (expandedClientId) {
            const card = document.querySelector(`.compact-card[data-client-id="${expandedClientId}"]`);
            if (card) {
                expandedCardElement = card;
                if (expandedDirection === 'up') card.classList.add('expanded','expand-up'); 
                else card.classList.add('expanded','expand-down');

                const chevron = card.querySelector('.chevron-icon'); if (chevron) chevron.classList.add('rotated');
                const expandable = card.querySelector('[data-expandable="true"]'); if (expandable) expandable.classList.add('expanded');
            }
        }
    }

    /** ===== CREATE CARD HTML ===== */
    function createCompactCard(client, isExpanded) {
        const initials = App.getInitials(client.name);
        const avatarColor = getAvatarColor(client.name);
        const phone = client.phone || '';
        const email = client.email || '';
        const dateTime = formatDateTime(client.registeredat);

        return `
        <div class="compact-card ${isExpanded?'expanded':''}" data-client-id="${client.id}">
            <div class="card-header" data-action="toggle">
                <div class="card-left">
                    <div class="card-avatar" style="background:${avatarColor}">${initials}</div>
                    <div class="card-info">
                        <h4 class="card-name">${App.escapeHtml(client.name)}</h4>
                        <div class="card-date">${phone || 'No phone'}</div>
                    </div>
                </div>
                <div class="chevron-icon ${isExpanded?'rotated':''}"><i class="fa-solid fa-chevron-down"></i></div>
            </div>
            <div class="card-expandable ${isExpanded?'expanded':''}" data-expandable="true">
                <div class="expandable-content">
                    ${email?`<div class="info-row"><div class="info-label"><i class="fa-solid fa-envelope"></i>Email</div><div class="info-value">${App.escapeHtml(email)}</div></div>`:''}
                    ${phone?`<div class="info-row"><div class="info-label"><i class="fa-solid fa-phone"></i>Phone</div><div class="info-value">${App.escapeHtml(phone)}</div></div>`:''}
                    <div class="info-row"><div class="info-label"><i class="fa-solid fa-clock"></i>Registered</div><div class="info-value">${dateTime}</div></div>
                </div>
            </div>
        </div>`;
    }

    /** ===== CALL/WHATSAPP ===== */
    function callClient(phone) {
        if (!phone) return App.showToast('No phone available','warning');
        window.location.href = `tel:${phone.replace(/\s/g,'')}`;
    }
    function whatsAppClient(phone) {
        if (!phone) return App.showToast('No phone available','warning');
        window.open(`https://wa.me/${phone.replace(/\D/g,'')}`, '_blank');
    }

    return { init, loadClients, toggleCard, callClient, whatsAppClient };
})();

window.ClientsModule = ClientsModule;
document.addEventListener('DOMContentLoaded', ()=> { if(document.getElementById('clients-container')) ClientsModule.init(); });